//name: 自动生成工具 - 悬浮窗版(最终修复版)
//author: DS
//description: 自动检查AI回复是否包含指定标签,缺失时自动删除并重新生成

(function() {
    // === 配置参数 ===
    const FLOAT_BTN_DEFAULT_TOP = 150;

    // === 常量 ===
    const STYLE_ID = 'auto-tag-checker-css-v13';
    const STORAGE_KEY = 'auto_tag_checker_settings_v13';
    const FLOAT_BTN_ID = 'atc-float-btn';

    // === 默认配置 ===
    const DEFAULT_SETTINGS = {
        tags: ['<thinking>', '</thinking>', '<content>', '</content>'],
        continueMessage: '继续',
        maxRetries: 5,
        maxContinues: 10,
        retryDelay: 500,
        isMinimized: false,
        isFloatBtn: false,
        position: { x: 20, y: 100 },
        floatBtnPosition: { x: null, y: null },
        theme: 'green'
    };

    // === 状态管理 ===
    const State = {
        // 运行状态
        isRunning: false,
        // 事件监听器
        eventListener: null,
        // 统计数据
        stats: {
            totalChecks: 0,
            continueCount: 0,
            failCount: 0
        },
        // 当前会话状态
        current: {
            retryCount: 0,
            processedMessageIds: new Set(), // 记录所有处理过的消息ID
            lastProcessedMessageId: null, // 【新增】记录最后处理的消息ID
            isProcessing: false,
            lastAction: null, // 记录最后一次操作类型: 'continue', 'regenerate', 'stop'
            lastActionTime: 0 // 最后一次操作时间
        },

        // 重置会话状态
        resetSession() {
            this.current = {
                retryCount: 0,
                processedMessageIds: new Set(),
                isProcessing: false,
                lastAction: null,
                lastActionTime: 0
            };
        },

        // 完全重置
        resetAll() {
            this.isRunning = false;
            this.stats = {
                totalChecks: 0,
                continueCount: 0,
                failCount: 0
            };
            this.resetSession();
            if (this.eventListener) {
                this.eventListener.stop();
                this.eventListener = null;
            }
        }
    };

    // === 工具函数 ===
    const Utils = {
        loadSettings() {
            try {
                const raw = localStorage.getItem(STORAGE_KEY);
                return raw ? { ...DEFAULT_SETTINGS, ...JSON.parse(raw) } : { ...DEFAULT_SETTINGS };
            } catch {
                return { ...DEFAULT_SETTINGS };
            }
        },

        saveSettings(settings) {
            try {
                localStorage.setItem(STORAGE_KEY, JSON.stringify(settings));
                return true;
            } catch (e) {
                console.error('[自动生成] 保存设置失败:', e);
                return false;
            }
        },

        checkTags(message, tags) {
            const missingTags = tags.filter(tag => !message.includes(tag));
            return {
                allPresent: missingTags.length === 0,
                missingTags
            };
        },

        addLog(message, type = 'info') {
            const timestamp = new Date().toLocaleTimeString();
            const logText = `[${timestamp}] ${message}`;
            const escapedLog = _.escape(logText);

            $('.atc-log, .atc-mini-log').each(function() {
                const $log = $(this);
                $log.append(`<div class="atc-log-entry ${type}">${escapedLog}</div>`);
                $log.scrollTop($log[0].scrollHeight);

                const entries = $log.find('.atc-log-entry');
                if (entries.length > 50) {
                    entries.first().remove();
                }
            });
        },

        updateStats() {
            $('.atc-stat-value.checks, .atc-mini-stat-value.checks').text(State.stats.totalChecks);
            $('.atc-stat-value.continues, .atc-mini-stat-value.continues').text(State.stats.continueCount);
            $('.atc-stat-value.retries, .atc-mini-stat-value.retries').text(State.stats.failCount);
        },

        // 获取最新AI消息
        getLatestAIMessage() {
            const messages = window.TavernHelper.getChatMessages('-1');
            if (!messages || messages.length === 0) return null;

            // 找到最新的AI消息
            for (const msg of messages) {
                if (msg.role === 'assistant') {
                    return msg;
                }
            }
            return null;
        },

        // 检查是否是重复消息
        isDuplicateMessage(messageId) {
            return State.current.processedMessageIds.has(messageId);
        },

        // 记录已处理的消息
        markMessageProcessed(messageId) {
            State.current.processedMessageIds.add(messageId);
            // 限制Set大小，防止内存泄漏
            if (State.current.processedMessageIds.size > 100) {
                const iterator = State.current.processedMessageIds.values();
                const firstValue = iterator.next().value;
                State.current.processedMessageIds.delete(firstValue);
            }
        },

        // 检查操作冷却时间
        isActionCooldown(actionType, cooldownMs = 1000) {
            const now = Date.now();
            if (State.current.lastAction === actionType && 
                now - State.current.lastActionTime < cooldownMs) {
                return true;
            }
            return false;
        },

        // 记录操作
        recordAction(actionType) {
            State.current.lastAction = actionType;
            State.current.lastActionTime = Date.now();
        }
    };

    // === 核心逻辑 ===
    const Core = {
        // 发送继续指令
        async sendContinue() {
            const settings = Utils.loadSettings();

            try {
                Utils.addLog(`发送继续指令: "${settings.continueMessage}"`, 'info');

                // 记录操作，防止重复
                if (Utils.isActionCooldown('continue', 2000)) {
                    Utils.addLog('继续指令发送太频繁，跳过', 'warn');
                    return false;
                }

                // 发送继续消息
                await window.TavernHelper.triggerSlash(`/send ${settings.continueMessage}`);

                // 短暂延迟后触发
                await new Promise(r => setTimeout(r, 300));
                await window.TavernHelper.triggerSlash('/trigger');

                Utils.recordAction('continue');
                Utils.addLog('✓ 继续指令已发送', 'success');
                return true;
            } catch (e) {
                Utils.addLog(`❌ 发送继续失败: ${e.message}`, 'error');
                return false;
            }
        },

        // 触发重新生成
        async triggerRegenerate() {
		    try {
		        Utils.addLog('执行删除并重新生成...', 'info');

		        if (!window.TavernHelper || !window.TavernHelper.triggerSlash) {
		            Utils.addLog('❌ TavernHelper未加载', 'error');
		            return false;
		        }

		        // 记录操作，防止重复
		        if (Utils.isActionCooldown('regenerate', 2000)) {
		            Utils.addLog('重新生成操作太频繁，跳过', 'warn');
		            return false;
		        }

		        // 【修复】记住当前消息ID，准备在删除后移除
		        const currentMessageId = State.current.lastProcessedMessageId;

		        // 删除最后一条消息
		        await window.TavernHelper.triggerSlash('/del 1');
		        await new Promise(r => setTimeout(r, 400));

		        // 触发新的生成
		        await window.TavernHelper.triggerSlash('/trigger');

		        // 【修复】从已处理集合中移除被删除的消息ID，允许新消息被处理
		        if (currentMessageId && State.current.processedMessageIds.has(currentMessageId)) {
		            State.current.processedMessageIds.delete(currentMessageId);
		            Utils.addLog(`清除消息 #${currentMessageId} 的记录，等待新回复`, 'info');
		        }

		        Utils.recordAction('regenerate');
		        Utils.addLog('✓ 重新生成已触发', 'success');
		        return true;
		    } catch (e) {
		        Utils.addLog(`❌ 重新生成失败: ${e.message}`, 'error');
		        return false;
		    }
		},

        // 停止脚本
        stopScript(reason) {
            Utils.addLog(`🛑 停止脚本: ${reason}`, 'error');
            Core.stop();
            toastr.warning(reason);
        },

        // 处理AI回复
        async handleAIResponse() {
            // 检查运行状态
            if (!State.isRunning) {
                return;
            }

            // 防止重复处理
            if (State.current.isProcessing) {
                Utils.addLog('正在处理中，跳过本次触发', 'info');
                return;
            }

            try {
                State.current.isProcessing = true;

                const settings = Utils.loadSettings();

                // 获取最新AI消息
                const latestMessage = Utils.getLatestAIMessage();
                if (!latestMessage) {
                    Utils.addLog('未找到AI消息', 'info');
                    return;
                }

                // 检查是否是重复消息
                if (Utils.isDuplicateMessage(latestMessage.message_id)) {
                    Utils.addLog(`消息 #${latestMessage.message_id} 已处理过，跳过`, 'info');
                    return;
                }

                // 标记消息为已处理
                Utils.markMessageProcessed(latestMessage.message_id);
                // 【修复】同时记录最后处理的消息ID，用于重试时清除
				State.current.lastProcessedMessageId = latestMessage.message_id;

                // 更新统计
                State.stats.totalChecks++;
                Utils.addLog(`检查消息 #${latestMessage.message_id}`, 'info');
                Utils.updateStats();

                // 检查标签
                const result = Utils.checkTags(latestMessage.message, settings.tags);

                if (result.allPresent) {
                    // === 标签完整的情况 ===
                    Utils.addLog(`✓ 标签完整 (${State.stats.continueCount + 1}/${settings.maxContinues})`, 'success');

                    // 重置重试计数
                    State.current.retryCount = 0;

                    // 检查是否达到最大继续次数
                    if (State.stats.continueCount >= settings.maxContinues) {
                        this.stopScript(`已完成${settings.maxContinues}次继续`);
                        return;
                    }

                    // 更新继续计数
                    State.stats.continueCount++;
                    Utils.updateStats();

                    // 延迟发送继续指令，避免事件循环
                    setTimeout(async () => {
                        if (State.isRunning) {
                            await this.sendContinue();
                        }
                    }, settings.retryDelay);

                } else {
                    // === 标签缺失的情况 ===
                    Utils.addLog(`✗ 缺少标签: ${result.missingTags.join(', ')}`, 'error');

                    // 检查是否达到最大重试次数
                    if (settings.maxRetries === 0 || State.current.retryCount >= settings.maxRetries) {
                        State.stats.failCount++;
                        Utils.updateStats();
                        this.stopScript(`已达最大重试次数(${settings.maxRetries})`);
                        return;
                    }

                    // 更新重试计数
                    State.current.retryCount++;
                    State.stats.failCount++;
                    Utils.addLog(`🔄 重试 ${State.current.retryCount}/${settings.maxRetries}`, 'info');
                    Utils.updateStats();

                    // 等待延迟后触发重新生成
                    setTimeout(async () => {
                        if (State.isRunning) {
                            await this.triggerRegenerate();
                        }
                    }, settings.retryDelay);
                }

            } catch (error) {
                Utils.addLog(`❌ 错误: ${error.message}`, 'error');
                console.error('[自动生成] 错误:', error);
            } finally {
                // 延迟释放处理锁
                setTimeout(() => {
                    State.current.isProcessing = false;
                }, 1000);
            }
        },

        // 启动
        async start() {
		    if (State.isRunning) {
		        toastr.warning('脚本已运行中');
		        return false;
		    }

		    const settings = Utils.loadSettings();

		    if (settings.tags.length === 0) {
		        toastr.error('请至少添加一个标签');
		        return false;
		    }

		    if (typeof window.TavernHelper === 'undefined') {
		        toastr.error('TavernHelper 未加载');
		        return false;
		    }

		    // 【修改】重置所有状态，包括统计数据
		    State.resetAll();  // 使用 resetAll 而不是 resetSession

		    // 或者单独重置统计数据
		    // State.stats = {
		    //     totalChecks: 0,
		    //     continueCount: 0,
		    //     failCount: 0
		    // };

		    State.isRunning = true;

		    // 注册事件监听 - 使用防抖包装
		    const debouncedHandler = _.debounce(Core.handleAIResponse.bind(Core), 300);
		    State.eventListener = window.eventOn(
		        window.tavern_events.MESSAGE_RECEIVED,
		        debouncedHandler
		    );

		    Utils.addLog('=== 脚本已启动 ===', 'success');
		    Utils.addLog(`监听标签: ${settings.tags.join(', ')}`, 'info');
		    Utils.addLog(`最大继续: ${settings.maxContinues}次 | 最大重试: ${settings.maxRetries}次`, 'info');

		    // 【新增】更新统计显示
		    Utils.updateStats();

		    // 发送初始继续指令
		    Utils.addLog('发送初始继续指令...', 'info');
		    setTimeout(async () => {
		        if (State.isRunning) {
		            await this.sendContinue();
		        }
		    }, 500);

		    updateButtonStates();
		    updateFloatBtn();
		    toastr.success('✓ 自动生成已启动');

		    return true;
		},
		// 完全重置（用于启动新会话）
		resetAll() {
		    this.isRunning = false;
		    // 【修改】重置统计数据，但不清除 processedMessageIds
		    this.stats = {
		        totalChecks: 0,
		        continueCount: 0,
		        failCount: 0
		    };
		    // 【修改】重置会话状态，但保留 processedMessageIds 用于去重
		    this.current = {
		        retryCount: 0,
		        processedMessageIds: this.current?.processedMessageIds || new Set(), // 保留历史消息ID
		        lastProcessedMessageId: null,
		        isProcessing: false,
		        lastAction: null,
		        lastActionTime: 0
		    };
		    if (this.eventListener) {
		        this.eventListener.stop();
		        this.eventListener = null;
		    }
		},

        // 停止
        stop() {
            if (!State.isRunning) {
                return false;
            }

            if (State.eventListener && State.eventListener.stop) {
                State.eventListener.stop();
                State.eventListener = null;
            }

            State.isRunning = false;

            Utils.addLog('=== 脚本已停止 ===', 'error');
            Utils.addLog(`总计: 检查${State.stats.totalChecks}次 | 继续${State.stats.continueCount}次 | 重试${State.stats.failCount}次`, 'info');

            updateButtonStates();
            updateFloatBtn();
            toastr.info('已停止自动生成');

            return true;
        },

        // 重置统计
        resetStats() {
            State.stats = {
                totalChecks: 0,
                continueCount: 0,
                failCount: 0
            };
            Utils.updateStats();
            Utils.addLog('统计已重置', 'info');
        }
    };

    // === UI元素引用 ===
    let $floatWindow = null;
    let $floatBtn = null;
    let isDragging = false;
    let dragStart = { x: 0, y: 0, left: 0, top: 0 };

    // === UI函数（保持原有UI代码不变）===
    function createFloatBtn() {
        if ($floatBtn && $floatBtn.length > 0) return;

        const settings = Utils.loadSettings();

        $floatBtn = $(`<button id="${FLOAT_BTN_ID}" class="first-show" title="自动生成工具 · 可拖动 · 点击展开">
            <i class="fa-solid fa-robot"></i>
        </button>`);

        if (settings.floatBtnPosition.x !== null && settings.floatBtnPosition.y !== null) {
            $floatBtn.css({
                right: 'auto',
                top: settings.floatBtnPosition.y + 'px',
                left: settings.floatBtnPosition.x + 'px'
            });
        } else {
            const screenWidth = window.parent.innerWidth;
            const btnSize = 56;
            const rightMargin = 16;
            $floatBtn.css({
                right: 'auto',
                top: FLOAT_BTN_DEFAULT_TOP + 'px',
                left: (screenWidth - btnSize - rightMargin) + 'px'
            });
        }

        // 拖动逻辑（保持不变）
        let btnDrag = { startX: 0, startY: 0, isDragging: false, hasMoved: false };

        const startBtnDrag = (e) => {
            e.preventDefault();
            e.stopPropagation();

            btnDrag.isDragging = false;
            btnDrag.hasMoved = false;

            const clientX = e.type === 'touchstart' ? e.touches[0].clientX : e.clientX;
            const clientY = e.type === 'touchstart' ? e.touches[0].clientY : e.clientY;

            const offset = $floatBtn.offset();
            btnDrag.startX = clientX;
            btnDrag.startY = clientY;
            dragStart.left = offset.left;
            dragStart.top = offset.top;
        };

        const handleBtnDrag = (e) => {
            if (btnDrag.startX === 0) return;

            const clientX = e.type === 'touchmove' ? e.touches[0].clientX : e.clientX;
            const clientY = e.type === 'touchmove' ? e.touches[0].clientY : e.clientY;

            const deltaX = Math.abs(clientX - btnDrag.startX);
            const deltaY = Math.abs(clientY - btnDrag.startY);

            if (deltaX > 5 || deltaY > 5) {
                btnDrag.isDragging = true;
                btnDrag.hasMoved = true;
            }

            if (!btnDrag.isDragging) return;

            e.preventDefault();
            e.stopPropagation();

            let newLeft = dragStart.left + (clientX - btnDrag.startX);
            let newTop = dragStart.top + (clientY - btnDrag.startY);

            const maxX = window.parent.innerWidth - $floatBtn.outerWidth();
            const maxY = window.parent.innerHeight - $floatBtn.outerHeight();

            newLeft = Math.max(0, Math.min(newLeft, maxX));
            newTop = Math.max(0, Math.min(newTop, maxY));

            $floatBtn.css({ left: newLeft + 'px', top: newTop + 'px', right: 'auto' });
        };

        const stopBtnDrag = (e) => {
            if (btnDrag.startX === 0) return;

            if (btnDrag.isDragging && btnDrag.hasMoved) {
                const settings = Utils.loadSettings();
                const offset = $floatBtn.offset();
                settings.floatBtnPosition = {
                    x: Math.round(offset.left),
                    y: Math.round(offset.top)
                };
                Utils.saveSettings(settings);
            }

            if (!btnDrag.hasMoved) {
                e.preventDefault();
                e.stopPropagation();

                const settings = Utils.loadSettings();
                settings.isFloatBtn = false;
                Utils.saveSettings(settings);

                $(window.parent.document)
                    .off('mousemove.atcBtn touchmove.atcBtn')
                    .off('mouseup.atcBtn touchend.atcBtn');

                $floatBtn.remove();
                $floatBtn = null;
                showUI();
            }

            btnDrag = { startX: 0, startY: 0, isDragging: false, hasMoved: false };
        };

        $floatBtn.on('mousedown touchstart', startBtnDrag);

        $(window.parent.document)
            .on('mousemove.atcBtn touchmove.atcBtn', handleBtnDrag)
            .on('mouseup.atcBtn touchend.atcBtn', stopBtnDrag);

        $(window.parent.document.body).append($floatBtn);

        setTimeout(() => {
            if ($floatBtn && $floatBtn.length > 0) {
                $floatBtn.removeClass('first-show');
            }
        }, 4500);
    }

    function updateFloatBtn() {
        if ($floatBtn && $floatBtn.length > 0) {
            if (State.isRunning) {
                $floatBtn.addClass('running').attr('title', '自动生成工具 - 运行中 - 点击展开');
            } else {
                $floatBtn.removeClass('running').attr('title', '自动生成工具 - 已停止 - 点击展开');
            }
        }
    }

    function updateButtonStates() {
        if ($floatWindow && $floatWindow.length > 0) {
            $floatWindow.find('.atc-btn-start').prop('disabled', State.isRunning);
            $floatWindow.find('.atc-btn-stop').prop('disabled', !State.isRunning);
        }
    }

    function showUI() {
        if ($floatWindow && $floatWindow.length > 0) {
            $floatWindow.show();
            return;
        }

        if ($floatBtn && $floatBtn.length > 0) {
            $floatBtn.remove();
            $floatBtn = null;
        }

        const settings = Utils.loadSettings();
        settings.isFloatBtn = false;
        Utils.saveSettings(settings);

        createFloatWindow();
    }

    function createFloatWindow() {
        const settings = Utils.loadSettings();

        $floatWindow = $('<div>')
            .addClass('atc-float-window')
            .addClass(`theme-${settings.theme || 'green'}`)
            .addClass(settings.isMinimized ? 'minimized' : 'normal')
            .css({
                left: settings.position.x + 'px',
                top: settings.position.y + 'px'
            })
            .appendTo(window.parent.document.body);

        // 标题栏
        const $header = $('<div>').addClass('atc-header').appendTo($floatWindow);

        $('<div>').addClass('atc-title')
            .html('<i class="fa-solid fa-robot"></i> 自动生成')
            .appendTo($header);

        const $controls = $('<div>').addClass('atc-header-controls').appendTo($header);

        $('<button>').addClass('atc-control-btn theme')
            .html('<i class="fa-solid fa-palette"></i>')
            .attr('title', '切换主题')
            .appendTo($controls);

        $('<button>').addClass('atc-control-btn minimize')
            .text(settings.isMinimized ? '展开' : '缩小')
            .appendTo($controls);

        $('<button>').addClass('atc-control-btn reset')
            .html('<i class="fa-solid fa-location-crosshairs"></i>')
            .attr('title', '重置悬浮按钮位置')
            .appendTo($controls);

        $('<button>').addClass('atc-control-btn shrink')
            .html('<i class="fa-solid fa-compress"></i>')
            .attr('title', '缩小到悬浮按钮')
            .appendTo($controls);

        $('<button>').addClass('atc-control-btn close')
            .text('关闭')
            .appendTo($controls);

        // 内容区
        const $content = $('<div>').addClass('atc-content').appendTo($floatWindow);

        // 最小化视图
        $('<div>').addClass('atc-group atc-mini-view').html(`
            <div class="atc-mini-stats-row">
                <div class="atc-mini-stat">
                    <div class="atc-mini-stat-value checks">${State.stats.totalChecks}</div>
                    <div class="atc-mini-stat-label">总检查</div>
                </div>
                <div class="atc-mini-stat">
                    <div class="atc-mini-stat-value continues">${State.stats.continueCount}</div>
                    <div class="atc-mini-stat-label">继续次数</div>
                </div>
                <div class="atc-mini-stat">
                    <div class="atc-mini-stat-value retries">${State.stats.failCount}</div>
                    <div class="atc-mini-stat-label">重试次数</div>
                </div>
            </div>
            <div class="atc-mini-log"></div>
            <div class="atc-mini-actions">
                <button class="atc-btn-main atc-btn-start atc-mini-btn-start" ${State.isRunning ? 'disabled' : ''}>
                    <i class="fa-solid fa-play"></i> 启动
                </button>
                <button class="atc-btn-main atc-btn-stop atc-mini-btn-stop" ${!State.isRunning ? 'disabled' : ''}>
                    <i class="fa-solid fa-stop"></i> 停止
                </button>
            </div>
        `).appendTo($content);

        // 标签管理
        $('<div>').addClass('atc-group').html(`
            <div class="atc-group-title">
                <i class="fa-solid fa-tags"></i> 检查标签
            </div>
            <div class="atc-group-desc">
                缺少任意标签将自动删除并重新生成
            </div>
