    function renderTags() {
        const settings = Utils.loadSettings();
        const $list = $('.atc-tags-list');
        $list.empty();

        if (settings.tags.length === 0) {
            $list.addClass('empty');
        } else {
            $list.removeClass('empty');
            settings.tags.forEach((tag, index) => {
                const $chip = $(`<div class="atc-tag-chip">
                    <span>${_.escape(tag)}</span>
                    <div class="atc-tag-remove" data-index="${index}">
                        <i class="fa-solid fa-times"></i>
                    </div>
                </div>`);

                $chip.find('.atc-tag-remove').on('click', function() {
                    const idx = parseInt($(this).data('index'));
                    const currentSettings = Utils.loadSettings();
                    currentSettings.tags.splice(idx, 1);
                    Utils.saveSettings(currentSettings);
                    renderTags();
                });

                $list.append($chip);
            });
        }
    }

    function bindEvents() {
        $floatWindow.find('.atc-add-tag-btn').on('click', function() {
            const $input = $floatWindow.find('.atc-tag-input');
            const tag = $input.val().trim();

            if (!tag) {
                toastr.warning('请输入标签');
                return;
            }

            const settings = Utils.loadSettings();
            if (settings.tags.includes(tag)) {
                toastr.warning('标签已存在');
                return;
            }

            settings.tags.push(tag);
            Utils.saveSettings(settings);
            $input.val('');
            renderTags();
            toastr.success('已添加');
        });

        $floatWindow.find('.atc-tag-input').on('keypress', function(e) {
            if (e.which === 13) {
                $floatWindow.find('.atc-add-tag-btn').click();
            }
        });

        $floatWindow.find('.atc-config-input').on('change', function() {
            const settings = Utils.loadSettings();
            settings.continueMessage = $floatWindow.find('.atc-continue-msg').val().trim() || '继续';

            const maxRetriesVal = parseInt($floatWindow.find('.atc-max-retries').val());
            settings.maxRetries = isNaN(maxRetriesVal) ? 5 : maxRetriesVal;

            const maxContinuesVal = parseInt($floatWindow.find('.atc-max-continues').val());
            settings.maxContinues = isNaN(maxContinuesVal) ? 10 : maxContinuesVal;

            const retryDelayVal = parseInt($floatWindow.find('.atc-retry-delay').val());
            settings.retryDelay = isNaN(retryDelayVal) ? 500 : retryDelayVal;

            Utils.saveSettings(settings);
        });

        $floatWindow.find('.atc-btn-start').on('click', async function() {
            if (await Core.start()) {
                updateButtonStates();
            }
        });

        $floatWindow.find('.atc-btn-stop').on('click', function() {
            if (Core.stop()) {
                updateButtonStates();
            }
        });
    }

    function cycleTheme() {
        const themes = ['green', 'blue', 'dark'];
        const settings = Utils.loadSettings();
        const currentIndex = themes.indexOf(settings.theme || 'green');
        const nextIndex = (currentIndex + 1) % themes.length;
        settings.theme = themes[nextIndex];

        $floatWindow.removeClass('theme-green theme-blue theme-dark');
        $floatWindow.addClass(`theme-${settings.theme}`);

        Utils.saveSettings(settings);
        toastr.info(`已切换到${settings.theme === 'green' ? '绿色' : settings.theme === 'blue' ? '蓝色' : '深色'}主题`);
    }

    function toggleMinimize() {
        const settings = Utils.loadSettings();
        settings.isMinimized = !settings.isMinimized;

        if (settings.isMinimized) {
            $floatWindow.removeClass('normal').addClass('minimized');
            $floatWindow.find('.minimize').text('展开');
        } else {
            $floatWindow.removeClass('minimized').addClass('normal');
            $floatWindow.find('.minimize').text('缩小');
        }

        Utils.saveSettings(settings);
    }

    function resetFloatBtnPosition() {
