    function startDrag(e) {
        if ($(e.target).closest('.atc-control-btn').length > 0) {
            return;
        }

        e.preventDefault();
        isDragging = true;

        const clientX = e.type === 'touchstart' ? e.touches[0].clientX : e.clientX;
        const clientY = e.type === 'touchstart' ? e.touches[0].clientY : e.clientY;

        const offset = $floatWindow.offset();
        dragStart.x = clientX;
        dragStart.y = clientY;
        dragStart.left = offset.left;
        dragStart.top = offset.top;
    }

    function handleDrag(e) {
        if (!isDragging) return;
        e.preventDefault();

        const clientX = e.type === 'touchmove' ? e.touches[0].clientX : e.clientX;
        const clientY = e.type === 'touchmove' ? e.touches[0].clientY : e.clientY;

        let newLeft = dragStart.left + (clientX - dragStart.x);
        let newTop = dragStart.top + (clientY - dragStart.y);

        const maxX = window.parent.innerWidth - $floatWindow.outerWidth();
        const maxY = window.parent.innerHeight - $floatWindow.outerHeight();

        newLeft = Math.max(0, Math.min(newLeft, maxX));
        newTop = Math.max(0, Math.min(newTop, maxY));

        $floatWindow.css({ left: newLeft + 'px', top: newTop + 'px' });
    }

    function stopDrag() {
        if (isDragging) {
            const settings = Utils.loadSettings();
            const offset = $floatWindow.offset();
            settings.position = {
                x: Math.round(offset.left),
                y: Math.round(offset.top)
            };
            Utils.saveSettings(settings);
        }

        isDragging = false;
    }

