                font-size: 12px;
                color: var(--theme-text);
            }

            .atc-float-window.theme-dark .atc-config-input {
                background: rgba(50, 50, 60, 0.9);
            }

            .atc-config-input:focus {
                outline: none;
                border-color: var(--theme-primary-hex);
            }

            /* 统计信息 */
            .atc-stats {
                display: grid;
                grid-template-columns: repeat(3, 1fr);
                gap: 6px;
                padding: 8px;
                background: rgba(var(--theme-primary), 0.08);
                border-radius: 6px;
                border: 1px solid rgba(var(--theme-primary), 0.2);
            }

            .atc-stat-item {
                text-align: center;
                display: flex;
                flex-direction: column;
                gap: 2px;
            }

            .atc-stat-value {
                font-size: 18px;
                font-weight: bold;
                color: var(--theme-primary-hex);
            }

            .atc-stat-label {
                font-size: 10px;
                opacity: 0.7;
                color: var(--theme-text-secondary);
            }

            /* 主按钮 */
            .atc-actions {
                display: flex;
                gap: 8px;
                padding-bottom: 60px;
                margin-bottom: 20px;
            }

            .atc-btn-main {
                flex: 1;
                padding: 10px;
                border: none;
                border-radius: 6px;
                font-weight: bold;
                font-size: 13px;
                cursor: pointer;
                transition: all 0.2s;
                display: flex;
                align-items: center;
                justify-content: center;
                gap: 6px;
            }

            .atc-btn-start {
                background: var(--theme-btn-bg);
                color: white;
            }

            .atc-btn-start:hover:not(:disabled) {
                background: var(--theme-btn-hover);
            }

            .atc-btn-start:disabled {
                opacity: 0.5;
                cursor: not-allowed;
            }

            .atc-btn-stop {
                background: #d9534f;
                color: white;
            }

            .atc-btn-stop:hover:not(:disabled) {
                background: #c9302c;
            }

            .atc-btn-stop:disabled {
                opacity: 0.5;
                cursor: not-allowed;
            }

            /* 日志 */
            .atc-log {
                max-height: 120px;
                overflow-y: auto;
                background: var(--theme-group-bg);
                padding: 6px;
                border-radius: 4px;
                font-size: 11px;
                font-family: monospace;
                line-height: 1.5;
                border: 1px solid var(--theme-border);
            }

            .atc-log::-webkit-scrollbar { width: 3px; }
            .atc-log::-webkit-scrollbar-thumb { 
                background: rgba(128, 128, 128, 0.3);
                border-radius: 2px;
            }

            .atc-log-entry {
                padding: 2px 0;
                opacity: 0.9;
                color: var(--theme-text);
            }

            .atc-log-entry.success { color: #4a8a5a; font-weight: 500; }
            .atc-log-entry.error { color: #d9534f; font-weight: 500; }
            .atc-log-entry.info { color: #5b8db8; }

            .atc-float-window.theme-dark .atc-log-entry.success { color: #86efac; }
            .atc-float-window.theme-dark .atc-log-entry.error { color: #fca5a5; }
            .atc-float-window.theme-dark .atc-log-entry.info { color: #93c5fd; }
        `;
    }

    // === 注册 ===
    function register() {
        console.log('[自动生成] 注册中...');
        addStyles();

        if (window.SillyTavern && window.SillyTavern.SlashCommandParser) {
            window.SillyTavern.SlashCommandParser.addCommandObject(
                window.SillyTavern.SlashCommand.fromProps({
                    name: 'tag-checker',
                    callback: showUI,
                    helpString: '打开自动生成工具'
                })
            );
        }

        if (typeof appendInexistentScriptButtons === 'function' && typeof getButtonEvent === 'function') {
            const BUTTON_NAME = '自动生成';
            appendInexistentScriptButtons([{ name: BUTTON_NAME, visible: true }]);
            eventOn(getButtonEvent(BUTTON_NAME), showUI);
        }

        console.log('[自动生成] 注册完成');
    }

    // 启动
    $(function() {
        if ('complete' === window.parent.document.readyState) {
            setTimeout(register, 1000);
        } else {
            $(window.parent).on('load', function() {
                setTimeout(register, 1000);
            });
        }
    });
})();
